class Solution:
    def wordBreak(self, s: str, wordDict: List[str]) -> List[str]:
        words = set(wordDict)
        n = len(s)
        dp = [[] for _ in range(n + 1)]
        dp[0] = ['']
        for i in range(1, n + 1):
            for j in range(i):
                w = s[j:i]
                if w in words and dp[j]:
                    for sent in dp[j]:
                        dp[i].append((sent + ' ' + w).strip())
        return dp[n]

